// --- ボーカルポートレート (`#vocal-canvas`) 描画系 ---
const spriteCanvas = document.getElementById("vocal-canvas");
const spriteCtx = spriteCanvas.getContext("2d");
let spriteImg = new Image();
let spriteAnimId = 0;
let spriteCols = 8;
let cellWidth = 0;
let cellHeight = 0;
let selectedRow = 0;

let lastHitAttribute = null; // 勇猛: ロック用

function updateLockVisuals() {
    const hitareas = document.querySelectorAll('.touch-lane-hitarea');
    hitareas.forEach(el => {
        el.classList.remove('locked');
        if (el.dataset.attr === lastHitAttribute) {
            el.classList.add('locked');
        }
    });
}
let selectedCol = 0;
let activeState = "BGM";
let lastStateCols = { BGM: 0, VOCAL: 0, CHORUS: 0, VOCAL_UP: 0 };
let lastReselectTime = 0;
let currentSpriteLoaded = false;
let isTransitioning = false;
let transSourceCell = { row: 0, col: 0 };
let transTargetCell = { row: 0, col: 0 };
let transStartTime = 0;

function loadPortraitSprite(attr, emotion) {
    cancelAnimationFrame(spriteAnimId);
    currentSpriteLoaded = false;
    spriteImg = new Image();
    spriteImg.onload = () => {
        currentSpriteLoaded = true;
        spriteCanvas.width = 360;
        spriteCanvas.height = 398;
        spriteCols = 8;
        cellWidth = spriteImg.width / 8;
        cellHeight = spriteImg.height / 4;
        selectedRow = 0;
        selectedCol = 0;
        activeState = "BGM";
        lastReselectTime = Date.now();
        drawSpriteFrame();
    };
    spriteImg.onerror = () => {
        if (attr !== "elegant" || emotion !== "neutral") loadPortraitSprite("elegant", "neutral");
    };
    spriteImg.src = `${SPRITE_BASE_DIR}vocal_sprite_${attr}_${emotion}_8x4.webp`;
}

function getRawStateAtTime(time) {
    if (!isPlaying || isPaused || isCountingDown) return "BGM";
    const track = tracksData[Number(trackSelect.value)];
    if (!track) return "BGM";
    const fileName = getTrackFile(track);
    const singing = track.singingIntervals && track.singingIntervals[fileName] || [];
    const excited = track.excitementSegments && track.excitementSegments[fileName] || [];
    const chorus = track.chorusCandidates && track.chorusCandidates[fileName] || [];
    const isSinging = singing.some((r) => time >= r[0] && time <= r[1]);
    const isExcited = excited.some((r) => time >= r[0] && time <= r[1]);
    const isChorus = chorus.some((r) => time >= r[0] && time <= r[1]);
    if (isSinging && isExcited) return "VOCAL_UP";
    if (isSinging) return "VOCAL";
    if (isChorus) return "CHORUS";
    return "BGM";
}

function triggerRandomCellForState(state) {
    const rowMap = { BGM: 0, VOCAL: 1, CHORUS: 2, VOCAL_UP: 3 };
    const row = rowMap[state] || 0;
    let col = Math.floor(Math.random() * spriteCols);
    const prev = lastStateCols[state];
    for (let i = 0; (col === selectedCol || col === prev) && i < 10; i++) {
        col = Math.floor(Math.random() * spriteCols);
    }
    lastStateCols[state] = col;
    startSpriteTransition(row, col);
    lastReselectTime = Date.now();
}

function startSpriteTransition(row, col) {
    if (row === selectedRow && col === selectedCol) return;
    transSourceCell = { row: selectedRow, col: selectedCol };
    transTargetCell = { row, col };
    transStartTime = Date.now();
    isTransitioning = true;
}

function drawSpriteCell(cell, alpha, xOffset = 0) {
    const cw = spriteCanvas.width;
    const ch = spriteCanvas.height;
    const sx = cell.col * cellWidth;
    const sy = cell.row * cellHeight;
    const aspect = cellWidth / cellHeight;
    let dw = cw * 1.16;
    let dh = ch * 1.16;
    if (cw / ch > aspect) dw = ch * aspect * 1.16;
    else dh = (cw / aspect) * 1.16;

    let scale = 1;
    let yOffset = 0;
    if (isPlaying && !isCountingDown && !player.paused) {
        const track = tracksData[Number(trackSelect.value)];
        const fileName = track ? getTrackFile(track) : "";
        const bpm = track && track.bpms && track.bpms[fileName] ? track.bpms[fileName] : 120;
        const beat = (gameTime / (60 / bpm)) % 1;
        const vocalBoost = activeState === "VOCAL" || activeState === "VOCAL_UP" ? 1 : 0.38;
        scale = 1 + 0.035 * vocalBoost * Math.exp(-beat * 8);
        yOffset = dh * 0.018 * vocalBoost * Math.sin(beat * Math.PI);
    }

    dw *= scale;
    dh *= scale;
    const dx = (cw - dw) / 2 + xOffset;
    const dy = (ch - dh) / 2 + yOffset;
    spriteCtx.save();
    spriteCtx.globalAlpha = alpha;
    spriteCtx.imageSmoothingEnabled = true;
    spriteCtx.drawImage(spriteImg, sx, sy, cellWidth, cellHeight, dx, dy, dw, dh);
    spriteCtx.restore();
}

function drawSpriteFrame() {
    if (!currentSpriteLoaded || !spriteImg.complete) return;
    const frameNow = performance.now();
    if (frameNow - lastSpriteDraw < TARGET_FRAME_MS) {
        spriteAnimId = requestAnimationFrame(drawSpriteFrame);
        return;
    }
    lastSpriteDraw = frameNow;
    const cw = spriteCanvas.width;
    const ch = spriteCanvas.height;
    spriteCtx.clearRect(0, 0, cw, ch);
    spriteCtx.fillStyle = "#f4ecd8";
    spriteCtx.fillRect(0, 0, cw, ch);

    const now = Date.now();
    const targetState = getRawStateAtTime(gameTime || 0);
    if (targetState !== activeState) {
        activeState = targetState;
        triggerRandomCellForState(activeState);
    }
    const track = tracksData[Number(trackSelect.value)];
    const fileName = track ? getTrackFile(track) : "";
    const bpm = track && track.bpms && track.bpms[fileName] ? track.bpms[fileName] : 120;
    const t = Math.min(1, Math.max(0, (bpm - 80) / 50));
    const intervalMs = (5 - 2 * t) * 1000;
    if (isPlaying && !isCountingDown && !isTransitioning && now - lastReselectTime >= intervalMs) {
        triggerRandomCellForState(activeState);
    }

    if (isTransitioning) {
        const progress = Math.min(1, (now - transStartTime) / 180);
        drawSpriteCell(transSourceCell, 1, -cw * progress);
        drawSpriteCell(transTargetCell, 1, cw - cw * progress);
        if (progress >= 1) {
            selectedRow = transTargetCell.row;
            selectedCol = transTargetCell.col;
            isTransitioning = false;
        }
    } else {
        drawSpriteCell({ row: selectedRow, col: selectedCol }, 1);
    }
    spriteAnimId = requestAnimationFrame(drawSpriteFrame);
}

// 演奏終了判定用終了時間
function getTrackEndTime() {
    const lastNoteTime = currentNotes.length ? currentNotes[currentNotes.length - 1].time : 0;
    if (Number.isFinite(player.duration) && player.duration > 0) {
        return player.duration + RESULT_GRACE_SEC;
    }
    return lastNoteTime + RESULT_GRACE_SEC + 1.0;
}

// 一時停止・再開
function pauseGame() {
    if (!isPlaying || isPaused || isCountingDown || isApproaching) return;
    isPaused = true;
    player.pause();
    document.getElementById("pause-score").textContent = score;
    document.getElementById("pause-combo").textContent = combo;
    pauseModal.classList.add("active");
}

function resumeGame() {
    if (!isPlaying || !isPaused) return;
    isPaused = false;
    pauseModal.classList.remove("active");
    songStartPerformance = performance.now() - (gameTime * 1000);
    player.play().catch(() => {});
}

function restartGame() {
    pauseModal.classList.remove("active");
    startGame();
}

function exitGame() {
    pauseModal.classList.remove("active");
    stopGame();
}

// プレイ開始
playBtn.addEventListener("click", () => {
    if (isPlaying) {
        stopGame();
    } else {
        startGame();
    }
});

function startGame() {
    if (!tracksData.length) {
        lastJudge.textContent = "楽曲ロード中";
        loadTracksWhenReady();
        setTimeout(() => {
            if (tracksData.length && !isPlaying) startGame();
        }, 150);
        return;
    }
    const trackIndex = getSelectedTrackIndex();
    if (trackIndex < 0) {
        lastJudge.textContent = "楽曲未選択";
        return;
    }
    trackSelect.value = String(trackIndex);
    const track = tracksData[trackIndex];
    if (!track) {
        lastJudge.textContent = "楽曲未選択";
        return;
    }
    resetRunStats();
    
    const notes = getDensityNotes(track, densitySelect.value);
    currentNotes = notes.map((note, idx) => ({
        id: idx,
        time: Number(note.time),
        attribute: ATTR[note.attribute] ? note.attribute : "elegant",
        hit: false,
        missed: false,
        dom: null
    })).sort((a, b) => a.time - b.time);
    
    isPlaying = true;
    isPaused = false;
    isCountingDown = true;
    isApproaching = false;
    countdownStart = performance.now();
    lastGameLoopUpdate = 0;
    player.pause();
    player.currentTime = 0;
    player.muted = true;
    player.play().catch(() => {});
    activeState = "BGM";
    selectedRow = 0;
    selectedCol = 0;
    playBtn.textContent = "演奏停止";
    pauseModal.classList.remove("active");
    resultsModal.classList.remove("active");
    countdownOverlay.classList.add("active");
    countdownOverlay.classList.remove("approach");
    
    loopId = requestAnimationFrame(updateGameLoop);
}

function stopGame() {
    isPlaying = false;
    isPaused = false;
    isCountingDown = false;
    isApproaching = false;
    cancelAnimationFrame(loopId);
    player.pause();
    player.muted = false;
    player.volume = Number(bgmVol.value) / 100;
    document.getElementById("notes-layer").innerHTML = "";
    countdownOverlay.classList.remove("active", "approach");
    pauseModal.classList.remove("active");
    resultsModal.classList.remove("active");
    playBtn.textContent = "演奏開始";
    activeState = "BGM";
    updateHUD();
}

function updateNotes() {
    const laneWidth = laneContainer.clientWidth;
    const judgmentX = laneWidth * JUDGMENT_X_RATIO;
    const spawnX = laneWidth * NOTE_SPAWN_X_RATIO;
    const travelTime = Math.max(0.1, (judgmentX - spawnX) / noteSpeed);
    
    for (const note of currentNotes) {
        if (note.hit || note.missed) continue;
        if (note.time <= gameTime + travelTime) {
            if (!note.dom) {
                const el = document.createElement("div");
                el.className = `note ${note.attribute}`;
                el.style.top = `${ATTR[note.attribute].y * 100}%`;
                el.innerHTML = `<span class="note-icon" style="background-position:${ICON_POS[note.attribute]}"></span>`;
                document.getElementById("notes-layer").appendChild(el);
                note.dom = el;
            }
            const delta = note.time - gameTime;
            const x = judgmentX - delta * noteSpeed;
            note.dom.style.transform = `translate3d(${x}px, 0, 0)`;
            
            if (!note.pulseTriggered && Math.abs(delta) < 0.04) {
                note.pulseTriggered = true;
                const icon = document.querySelector(`.judgment-icon.${note.attribute}`);
                if (icon) {
                    icon.classList.add("shrink");
                    setTimeout(() => icon.classList.remove("shrink"), 100);
                }
            }
        }
        if (gameTime >= 0 && gameTime - note.time > LATE_MISS_MARGIN_SEC && !note.hit) {
            missNote(note);
        }
    }
}

function updateGameLoop(now) {
    if (!isPlaying || isPaused) return;
    if (now - lastGameLoopUpdate < TARGET_FRAME_MS) {
        loopId = requestAnimationFrame(updateGameLoop);
        return;
    }
    lastGameLoopUpdate = now;
    
    if (isCountingDown) {
        const elapsed = (now - countdownStart) / 1000;
        const left = COUNTDOWN_SEC - elapsed;
        gameTime = -left - APPROACH_SEC;
        countdownOverlay.classList.add("active");
        countdownOverlay.classList.remove("approach");
        if (left > 2.0) countdownText.textContent = "3";
        else if (left > 1.0) countdownText.textContent = "2";
        else if (left > 0) countdownText.textContent = "1";
        else {
            isCountingDown = false;
            isApproaching = true;
            approachStart = performance.now();
            countdownText.textContent = "GET READY";
            countdownOverlay.classList.add("approach");
        }
    } else if (isApproaching) {
        const elapsed = (performance.now() - approachStart) / 1000;
        gameTime = elapsed - APPROACH_SEC;
        countdownOverlay.classList.add("active", "approach");
        countdownText.textContent = "GET READY";
        if (elapsed >= APPROACH_SEC) {
            isApproaching = false;
            countdownOverlay.classList.remove("approach", "active");
            countdownText.textContent = "";
            songStartPerformance = performance.now();
            player.currentTime = 0;
            player.muted = false;
            player.volume = Number(bgmVol.value) / 100;
            if (player.paused) player.play().catch(() => {});
        }
    } else {
        const virtualTime = (performance.now() - songStartPerformance) / 1000;
        gameTime = player.paused ? virtualTime : player.currentTime;
    }

    updateNotes();
    updateHUD();

    if (player.ended || gameTime >= getTrackEndTime()) {
        setTimeout(() => { if (isPlaying) displayResults(); }, 650);
        return;
    }
    loopId = requestAnimationFrame(updateGameLoop);
}

function displayResults() {
    isPlaying = false;
    isPaused = false;
    player.pause();
    playBtn.textContent = "演奏開始";
    cancelAnimationFrame(loopId);

    const total = perfects + greats + goods + misses;
    const max = Math.max(1, total * 100);
    const ratio = score / max;
    let rank = "D";
    if (ratio >= 0.95) rank = "S";
    else if (ratio >= 0.82) rank = "A";
    else if (ratio >= 0.66) rank = "B";
    else if (ratio >= 0.48) rank = "C";

    const rankEl = document.getElementById("res-rank");
    rankEl.textContent = rank;
    rankEl.className = `result-rank rank-${rank}`;

    document.getElementById("res-perfect").textContent = perfects;
    document.getElementById("res-great").textContent = greats;
    document.getElementById("res-good").textContent = goods;
    document.getElementById("res-miss").textContent = misses;
    document.getElementById("res-maxcombo").textContent = maxCombo;
    document.getElementById("res-score").textContent = score;

    resultsModal.classList.add("active");
}

function applyTrackIcons(track) {
    const rawId = String(track && track.id || "");
    const parts = rawId.split("_");
    let insCode = 201;
    let typeCode = 211;
    let themeCode = 221;
    let isSpecial = false;
    let specialRegion = 1;
    let specialAttr = "elegant";

    if (parts.length >= 4) {
        if (parts[1] === "special") {
            isSpecial = true;
            specialRegion = parseInt(parts[2], 10) || 1;
            specialAttr = parts[3] || "elegant";
        } else {
            insCode = parseInt(parts[1], 10) || insCode;
            typeCode = parseInt(parts[2], 10) || typeCode;
            themeCode = parseInt(parts[3], 10) || themeCode;
        }
    }

    const iconDefs = {
        instrument: { sheet: "icon_sheet_03_music_bonus_code.webp", index: 18, title: "楽器" },
        type: { sheet: "icon_sheet_03_music_bonus_code.webp", index: 30, title: "曲種" },
        theme: { sheet: "icon_sheet_03_music_bonus_code.webp", index: 43, title: "テーマ" }
    };

    if (isSpecial) {
        iconDefs.instrument.index = 4;
        iconDefs.type.sheet = "icon_sheet_02_card_event_code.webp";
        iconDefs.type.index = 16 + (specialRegion - 1);
        iconDefs.theme.sheet = "icon_sheet_01_minigame_ui.webp";
        iconDefs.theme.index = specialAttr === "mystic" ? 26 : specialAttr === "brave" ? 24 : 25;
    } else {
        const instrumentMap = { 101: 16, 102: 17, 201: 18, 202: 19, 301: 20, 302: 21, 401: 22, 402: 23, 501: 24, 502: 25, 601: 26, 602: 27 };
        const typeMap = { 111: 28, 112: 29, 211: 30, 212: 31, 311: 32, 312: 33, 411: 34, 412: 35, 511: 36, 512: 37, 611: 38, 612: 39 };
        const themeMap = {
            121: 40, 122: 41, 123: 42,
            221: 43, 222: 44, 223: 45,
            321: 46, 322: 47, 323: 48,
            421: 49, 422: 50, 423: 51,
            521: 52, 522: 53, 523: 54,
            621: 55, 622: 56, 623: 57
        };
        iconDefs.instrument.index = instrumentMap[insCode] ?? iconDefs.instrument.index;
        iconDefs.type.index = typeMap[typeCode] ?? iconDefs.type.index;
        iconDefs.theme.index = themeMap[themeCode] ?? iconDefs.theme.index;
    }

    function iconPosition(index) {
        const tile = 42;
        const col = index % 8;
        const row = Math.floor(index / 8);
        return `${-(col * tile)}px ${-(row * tile)}px`;
    }

    for (const [key, def] of Object.entries(iconDefs)) {
        const el = conditionIconEls[key];
        if (!el) continue;
        el.style.backgroundImage = `url("../assets/images/icon/${def.sheet}")`;
        el.style.backgroundPosition = iconPosition(def.index);
        el.title = def.title;
    }
}

function hexToRgb(hex, alpha) {
    const n = parseInt(hex.slice(1), 16);
    return `rgba(${(n >> 16) & 255}, ${(n >> 8) & 255}, ${n & 255}, ${alpha})`;
}

// --- キー割り当て・入力イベント設定 ---
function getAttributeForKey(code) {
    for (const attr of Object.keys(keyBindings)) {
        if (keyBindings[attr].key === code) return attr;
    }
    return "";
}

function getAttributeForMouse(btn) {
    for (const attr of Object.keys(keyBindings)) {
        if (keyBindings[attr].mouse === String(btn)) return attr;
    }
    return "";
}

function isTextEntryTarget(target) {
    if (!(target instanceof HTMLElement)) return false;
    if (target.isContentEditable) return true;
    return target.matches("input, textarea, select");
}

function blurFocusedActionForGameKey(code) {
    if (code !== "Space" && code !== "Enter") return;
    const active = document.activeElement;
    if (!(active instanceof HTMLElement)) return;
    if (active.matches("button, a, [role='button'], input[type='button'], input[type='submit']")) {
        active.blur();
    }
}

function isKeyboardInputBlocked(target) {
    if (configModal.classList.contains("active") || pauseModal.classList.contains("active") || resultsModal.classList.contains("active")) return true;
    return isTextEntryTarget(target);
}

function setKeyBinding(attr, code) {
    for (const k of Object.keys(keyBindings)) {
        if (k !== attr && keyBindings[k].key === code) keyBindings[k].key = ""; 
    }
    keyBindings[attr].key = code;
    waitingBindAttr = "";
    document.querySelectorAll(".bind-key-btn").forEach((btn) => btn.classList.remove("waiting"));
    if (document.activeElement instanceof HTMLElement) document.activeElement.blur();
    saveSettings();
    refreshBindingUI();
}

function setMouseBinding(attr, buttonValue) {
    for (const k of Object.keys(keyBindings)) {
        if (k !== attr && keyBindings[k].mouse === buttonValue && buttonValue !== "none") {
            keyBindings[k].mouse = "none";
        }
    }
    keyBindings[attr].mouse = buttonValue;
    saveSettings();
    refreshBindingUI();
}

function isTouchDevice() {
    const mobileUA = /Android|iPhone|iPad|iPod|Mobile|Windows Phone/i.test(navigator.userAgent);
    const compactTouch = navigator.maxTouchPoints > 0 &&
        window.matchMedia("(pointer: coarse)").matches &&
        Math.min(window.innerWidth, window.innerHeight) <= 820;
    return mobileUA || compactTouch;
}

function refreshBindingUI() {
    for (const attr of Object.keys(keyBindings)) {
        const keyBtn = document.querySelector(`[data-key-bind="${attr}"]`);
        const mouseSelect = document.querySelector(`[data-mouse-bind="${attr}"]`);
        if (keyBtn) {
            const code = keyBindings[attr].key;
            keyBtn.textContent = KEY_LABELS[code] || code.replace(/^Key/, "") || "未設定";
        }
        if (mouseSelect) mouseSelect.value = keyBindings[attr].mouse;
    }
}

function readSavedSettings() {
    try {
        return JSON.parse(localStorage.getItem(SETTINGS_STORAGE_KEY) || "{}");
    } catch {
        return {};
    }
}

function normalizeBindings(raw) {
    const next = JSON.parse(JSON.stringify(DEFAULT_BINDINGS));
    for (const attr of Object.keys(next)) {
        if (!raw || typeof raw[attr] !== "object") continue;
        if (typeof raw[attr].key === "string" && raw[attr].key) next[attr].key = raw[attr].key;
        if (typeof raw[attr].mouse === "string") next[attr].mouse = raw[attr].mouse;
    }
    return next;
}

function applySavedSettings() {
    const settings = readSavedSettings();
    if (settings.density) densitySelect.value = settings.density;
    if (settings.window) windowSelect.value = settings.window;
    if (settings.speed) {
        speedInput.value = settings.speed;
        noteSpeed = Number(settings.speed);
    }
    if (settings.offset) offsetInput.value = settings.offset;
    if (settings.bgm) {
        bgmVol.value = settings.bgm;
        player.volume = Number(settings.bgm) / 100;
    }
    if (settings.companionCount !== undefined) companionCountSelect.value = settings.companionCount;
    if (settings.audienceCount !== undefined) audienceCountSelect.value = String(Math.min(Number(settings.audienceCount) || 0, MAX_AUDIENCE_COUNT));
    keyJudgeTiming = settings.keyJudgeTiming === "up" ? "up" : "down";
    keyTimingSelect.value = keyJudgeTiming;
    keyBindings = normalizeBindings(settings.bindings);
}

function saveSettings() {
    const settings = {
        track: trackSelect.value,
        density: densitySelect.value,
        window: windowSelect.value,
        speed: speedInput.value,
        offset: offsetInput.value,
        bgm: bgmVol.value,
        keyJudgeTiming,
        bindings: keyBindings,
        companionCount: companionCountSelect.value,
        audienceCount: audienceCountSelect.value
    };
    localStorage.setItem(SETTINGS_STORAGE_KEY, JSON.stringify(settings));
}

function updateCompanionVisibility() {
    // Excalibur版ではCompanionActorの追加・削除で制御しているため、この関数はUI状態確認のみ
}

function syncControlLabels() {
    noteSpeed = Number(speedInput.value);
    speedVal.textContent = `${noteSpeed} px/s`;
    const offsetValue = Number(offsetInput.value);
    offsetVal.textContent = `${offsetValue > 0 ? "+" : ""}${offsetValue} ms`;
    bgmVolVal.textContent = `${bgmVol.value}%`;
    seVolVal.textContent = seVol.value === "0" ? "OFF" : `${seVol.value}%`;
}

function resetToDefaultSettings() {
    keyBindings = JSON.parse(JSON.stringify(DEFAULT_BINDINGS));
    densitySelect.value = "2";
    windowSelect.value = "150";
    speedInput.value = "300";
    noteSpeed = 300;
    speedVal.textContent = "300 px/s";
    offsetInput.value = "0";
    offsetVal.textContent = "0 ms";
    bgmVol.value = "80";
    bgmVolVal.textContent = "80%";
    player.volume = 0.8;
    companionCountSelect.value = "3";
    audienceCountSelect.value = String(MAX_AUDIENCE_COUNT);
    inputModeSelect.value = "mouse";
    document.body.setAttribute("data-input-mode", "mouse");
    keyTimingSelect.value = "down";
    keyJudgeTiming = "down";
    saveSettings();
    refreshBindingUI();
    randomizeStageCast();
    lastJudge.textContent = "設定リセット完了";
    setMeter(2, "#10b981");
}

function setInputMode(mode) {
    inputModeSelect.value = mode;
    document.body.dataset.inputMode = mode;
    inputModeStatus.querySelector("strong").textContent = mode === "touch" ? "TOUCH" : "PC";
    inputModeStatus.querySelector("span").textContent = mode === "touch" ? "LANE" : "KEY+MOUSE";
}

function updateInputModeFromDevice() {
    setInputMode(isTouchDevice() ? "touch" : "mouse");
}

// UI変更イベント連携
trackSelect.addEventListener("change", () => {
    selectTrack(Number(trackSelect.value));
    saveSettings();
});
densitySelect.addEventListener("change", () => {
    if (!isPlaying) {
        resetRunStats();
        updateHUD();
    }
    saveSettings();
});
windowSelect.addEventListener("change", saveSettings);
speedInput.addEventListener("input", () => {
    speedVal.textContent = `${speedInput.value} px/s`;
    noteSpeed = Number(speedInput.value);
    saveSettings();
});
offsetInput.addEventListener("input", () => {
    const value = Number(offsetInput.value);
    offsetVal.textContent = `${value > 0 ? "+" : ""}${value} ms`;
    saveSettings();
});
bgmVol.addEventListener("input", () => {
    bgmVolVal.textContent = `${bgmVol.value}%`;
    player.volume = Number(bgmVol.value) / 100;
    saveSettings();
});
companionCountSelect.addEventListener("change", () => {
    randomizeStageCast();
    saveSettings();
});
audienceCountSelect.addEventListener("change", () => {
    randomizeStageCast();
    saveSettings();
});
inputModeSelect.addEventListener("change", () => {
    document.body.setAttribute("data-input-mode", inputModeSelect.value);
    saveSettings();
});
keyTimingSelect.addEventListener("change", () => {
    keyJudgeTiming = keyTimingSelect.value;
    saveSettings();
});

calibrateBtn.addEventListener("click", resetToDefaultSettings);
randomizeBtn.addEventListener("click", () => {
    if (isPlaying || isPaused || isCountingDown || isApproaching) stopGame();
    if (tracksData.length) {
        const nextIndex = Math.floor(Math.random() * tracksData.length);
        trackSelect.value = String(nextIndex);
        selectTrack(nextIndex);
        saveSettings();
    } else {
        randomizeStageCast();
    }
});
configBtn.addEventListener("click", () => configModal.classList.add("active"));
configCloseBtn.addEventListener("click", () => configModal.classList.remove("active"));

fullscreenBtn.addEventListener("click", () => {
    if (!document.fullscreenElement) {
        document.documentElement.requestFullscreen().then(() => {
            if (screen.orientation && screen.orientation.lock) {
                screen.orientation.lock("landscape").catch(() => {});
            }
        }).catch(() => {});
    } else {
        document.exitFullscreen().then(() => {
            if (screen.orientation && screen.orientation.unlock) {
                screen.orientation.unlock();
            }
        }).catch(() => {});
    }
});

// PC キー割り当てボタン
document.querySelectorAll("[data-key-bind]").forEach((btn) => {
    btn.addEventListener("click", () => {
        document.querySelectorAll(".bind-key-btn").forEach((b) => b.classList.remove("waiting"));
        btn.classList.add("waiting");
        btn.textContent = "キー入力待ち...";
        waitingBindAttr = btn.dataset.keyBind;
    });
});

document.querySelectorAll(".mouse-bind-select").forEach((sel) => {
    sel.addEventListener("change", () => setMouseBinding(sel.dataset.mouseBind, sel.value));
});

// モーダルアクション
document.getElementById("resume-btn").addEventListener("click", resumeGame);
document.getElementById("restart-btn").addEventListener("click", restartGame);
document.getElementById("exit-btn").addEventListener("click", exitGame);
document.getElementById("res-retry-btn").addEventListener("click", () => {
    resultsModal.classList.remove("active");
    startGame();
});
document.getElementById("res-close-btn").addEventListener("click", () => resultsModal.classList.remove("active"));
